import React, { Component } from 'react';

const image = {
    backgroundImage: 'url(../../public/bloody.pdf)',  // Path relative to the `public` folder
    backgroundSize: 'cover',  // Ensures the image covers the entire component
    backgroundPosition: 'center',  // Centers the image
    height: '100vh',  // Sets the height to fill the viewport
    width: '100%',  // Sets the width to fill the container
    color: 'white',  // Optional: change text color for better contrast
};

export default class BloodyBackground extends Component {
    render() {
        return (
            <div style={image}>
            </div>
        )
    }
}
